-- ============================================================================
-- 0001_rls.sql — Row Level Security policies + helper function + auth trigger
--
-- This file is intentionally NOT generated by drizzle-kit and MUST be applied
-- AFTER 0000_init.sql. See docs/02-DATABASE.md §5 for the security spec.
-- ============================================================================

-- ---------------------------------------------------------------------------
-- Helper: current user's role, looked up from public.profiles.
-- SECURITY DEFINER so it bypasses RLS on profiles (otherwise infinite recursion).
-- ---------------------------------------------------------------------------
create or replace function public.user_role()
returns public.user_role
language sql
stable
security definer
set search_path = public
as $$
  select role from public.profiles where id = auth.uid();
$$;

grant execute on function public.user_role() to authenticated;

-- ---------------------------------------------------------------------------
-- Trigger: create a profile row whenever a new auth user is created.
-- The new user's first_name / last_name / role come from raw_user_meta_data
-- (set by the admin invite flow or signup).
-- ---------------------------------------------------------------------------
create or replace function public.handle_new_user()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
begin
  insert into public.profiles (id, email, first_name, last_name, role)
  values (
    new.id,
    new.email,
    coalesce(new.raw_user_meta_data->>'first_name', ''),
    coalesce(new.raw_user_meta_data->>'last_name', ''),
    coalesce((new.raw_user_meta_data->>'role')::public.user_role, 'student')
  )
  on conflict (id) do nothing;
  return new;
end;
$$;

drop trigger if exists on_auth_user_created on auth.users;
create trigger on_auth_user_created
  after insert on auth.users
  for each row execute function public.handle_new_user();

-- ---------------------------------------------------------------------------
-- Enable RLS on every table.
-- ---------------------------------------------------------------------------
alter table public.profiles                enable row level security;
alter table public.academic_years          enable row level security;
alter table public.classes                 enable row level security;
alter table public.subjects                enable row level security;
alter table public.class_subjects          enable row level security;
alter table public.teacher_assignments     enable row level security;
alter table public.student_enrollments     enable row level security;
alter table public.student_subject_access  enable row level security;
alter table public.chapters                enable row level security;
alter table public.sequences               enable row level security;
alter table public.resources               enable row level security;
alter table public.quizzes                 enable row level security;
alter table public.questions               enable row level security;
alter table public.question_options        enable row level security;
alter table public.quiz_attempts           enable row level security;
alter table public.quiz_answers            enable row level security;
alter table public.progress                enable row level security;
alter table public.notifications           enable row level security;
alter table public.activity_logs           enable row level security;

-- ===========================================================================
-- profiles
-- - admin: all
-- - every user can read their own profile
-- ===========================================================================
create policy "profiles_select_own_or_admin" on public.profiles
  for select to authenticated
  using (id = auth.uid() or public.user_role() = 'admin');

create policy "profiles_admin_all" on public.profiles
  for all to authenticated
  using (public.user_role() = 'admin')
  with check (public.user_role() = 'admin');

create policy "profiles_self_update" on public.profiles
  for update to authenticated
  using (id = auth.uid())
  with check (id = auth.uid() and role = (select role from public.profiles where id = auth.uid()));

-- ===========================================================================
-- academic_years — admin/manager write, everyone reads.
-- ===========================================================================
create policy "academic_years_select_all" on public.academic_years
  for select to authenticated using (true);

create policy "academic_years_admin_manager_all" on public.academic_years
  for all to authenticated
  using (public.user_role() in ('admin', 'manager'))
  with check (public.user_role() in ('admin', 'manager'));

-- ===========================================================================
-- subjects — admin/manager write; teachers/students read.
-- ===========================================================================
create policy "subjects_select_all" on public.subjects
  for select to authenticated using (true);

create policy "subjects_admin_manager_all" on public.subjects
  for all to authenticated
  using (public.user_role() in ('admin', 'manager'))
  with check (public.user_role() in ('admin', 'manager'));

-- ===========================================================================
-- classes
-- - admin/manager: full access
-- - teacher: read classes where assigned
-- - student: read class where enrolled
-- ===========================================================================
create policy "classes_admin_manager_all" on public.classes
  for all to authenticated
  using (public.user_role() in ('admin', 'manager'))
  with check (public.user_role() in ('admin', 'manager'));

create policy "classes_teacher_select" on public.classes
  for select to authenticated
  using (
    public.user_role() = 'teacher'
    and exists (
      select 1 from public.teacher_assignments ta
      where ta.teacher_id = auth.uid() and ta.class_id = classes.id
    )
  );

create policy "classes_student_select" on public.classes
  for select to authenticated
  using (
    public.user_role() = 'student'
    and exists (
      select 1 from public.student_enrollments se
      where se.student_id = auth.uid() and se.class_id = classes.id
    )
  );

