-- ===========================================================================
-- sequences — same scope as parent chapter.
-- ===========================================================================
create policy "sequences_admin_manager_all" on public.sequences
  for all to authenticated
  using (public.user_role() in ('admin', 'manager'))
  with check (public.user_role() in ('admin', 'manager'));

create policy "sequences_teacher_scope_all" on public.sequences
  for all to authenticated
  using (
    public.user_role() = 'teacher'
    and exists (
      select 1
      from public.chapters c
      join public.teacher_assignments ta
        on ta.class_id = c.class_id and ta.subject_id = c.subject_id
      where c.id = sequences.chapter_id and ta.teacher_id = auth.uid()
    )
  )
  with check (
    public.user_role() = 'teacher'
    and exists (
      select 1
      from public.chapters c
      join public.teacher_assignments ta
        on ta.class_id = c.class_id and ta.subject_id = c.subject_id
      where c.id = sequences.chapter_id and ta.teacher_id = auth.uid()
    )
  );

create policy "sequences_student_select" on public.sequences
  for select to authenticated
  using (
    public.user_role() = 'student'
    and exists (
      select 1
      from public.chapters c
      join public.student_subject_access ssa
        on ssa.class_id = c.class_id and ssa.subject_id = c.subject_id
      where c.id = sequences.chapter_id and ssa.student_id = auth.uid()
    )
  );

-- ===========================================================================
-- resources
-- - student: read only if published AND access granted AND in publish window
-- ===========================================================================
create policy "resources_admin_manager_all" on public.resources
  for all to authenticated
  using (public.user_role() in ('admin', 'manager'))
  with check (public.user_role() in ('admin', 'manager'));

create policy "resources_teacher_scope_all" on public.resources
  for all to authenticated
  using (
    public.user_role() = 'teacher'
    and exists (
      select 1
      from public.chapters c
      join public.teacher_assignments ta
        on ta.class_id = c.class_id and ta.subject_id = c.subject_id
      where c.id = resources.chapter_id and ta.teacher_id = auth.uid()
    )
  )
  with check (
    public.user_role() = 'teacher'
    and exists (
      select 1
      from public.chapters c
      join public.teacher_assignments ta
        on ta.class_id = c.class_id and ta.subject_id = c.subject_id
      where c.id = resources.chapter_id and ta.teacher_id = auth.uid()
    )
  );

create policy "resources_student_select_published" on public.resources
  for select to authenticated
  using (
    public.user_role() = 'student'
    and status = 'published'
    and published_at is not null
    and published_at <= now()
    and (unpublish_at is null or unpublish_at > now())
    and exists (
      select 1
      from public.chapters c
      join public.student_subject_access ssa
        on ssa.class_id = c.class_id and ssa.subject_id = c.subject_id
      where c.id = resources.chapter_id and ssa.student_id = auth.uid()
    )
  );

-- ===========================================================================
-- quizzes — same pattern; student only sees published quizzes inside window.
-- ===========================================================================
create policy "quizzes_admin_manager_all" on public.quizzes
  for all to authenticated
  using (public.user_role() in ('admin', 'manager'))
  with check (public.user_role() in ('admin', 'manager'));

create policy "quizzes_teacher_scope_all" on public.quizzes
  for all to authenticated
  using (
    public.user_role() = 'teacher'
    and exists (
      select 1 from public.teacher_assignments ta
      where ta.teacher_id = auth.uid()
        and ta.class_id = quizzes.class_id
        and ta.subject_id = quizzes.subject_id
    )
  )
  with check (
    public.user_role() = 'teacher'
    and exists (
      select 1 from public.teacher_assignments ta
      where ta.teacher_id = auth.uid()
        and ta.class_id = quizzes.class_id
        and ta.subject_id = quizzes.subject_id
    )
  );

create policy "quizzes_student_select_published" on public.quizzes
  for select to authenticated
  using (
    public.user_role() = 'student'
    and status = 'published'
    and (opens_at is null or opens_at <= now())
    and (closes_at is null or closes_at > now())
    and exists (
      select 1 from public.student_subject_access ssa
      where ssa.student_id = auth.uid()
        and ssa.class_id = quizzes.class_id
        and ssa.subject_id = quizzes.subject_id
    )
  );

-- ===========================================================================
-- questions — readable when parent quiz is readable.
-- ===========================================================================
create policy "questions_admin_manager_all" on public.questions
  for all to authenticated
  using (public.user_role() in ('admin', 'manager'))
  with check (public.user_role() in ('admin', 'manager'));

create policy "questions_teacher_scope_all" on public.questions
  for all to authenticated
  using (
    public.user_role() = 'teacher'
    and exists (
      select 1
      from public.quizzes q
      join public.teacher_assignments ta
        on ta.class_id = q.class_id and ta.subject_id = q.subject_id
      where q.id = questions.quiz_id and ta.teacher_id = auth.uid()
    )
  )
  with check (
    public.user_role() = 'teacher'
    and exists (
      select 1
      from public.quizzes q
      join public.teacher_assignments ta
        on ta.class_id = q.class_id and ta.subject_id = q.subject_id
      where q.id = questions.quiz_id and ta.teacher_id = auth.uid()
    )
  );

create policy "questions_student_select" on public.questions
  for select to authenticated
  using (
    public.user_role() = 'student'
    and exists (
      select 1 from public.quizzes q
      where q.id = questions.quiz_id
        and q.status = 'published'
        and (q.opens_at is null or q.opens_at <= now())
        and (q.closes_at is null or q.closes_at > now())
        and exists (
          select 1 from public.student_subject_access ssa
          where ssa.student_id = auth.uid()
            and ssa.class_id = q.class_id
            and ssa.subject_id = q.subject_id
        )
    )
  );

-- ===========================================================================
-- question_options
-- IMPORTANT: students MUST NOT receive is_correct before they submit.
-- The student-facing read goes through the service role / Server Actions
-- which strip is_correct. No "for select" policy granted to students here.
-- ===========================================================================
create policy "question_options_admin_manager_all" on public.question_options
  for all to authenticated
  using (public.user_role() in ('admin', 'manager'))
  with check (public.user_role() in ('admin', 'manager'));

create policy "question_options_teacher_scope_all" on public.question_options
  for all to authenticated
  using (
    public.user_role() = 'teacher'
    and exists (
      select 1
      from public.questions qu
      join public.quizzes q on q.id = qu.quiz_id
      join public.teacher_assignments ta
        on ta.class_id = q.class_id and ta.subject_id = q.subject_id
      where qu.id = question_options.question_id and ta.teacher_id = auth.uid()
    )
  )
  with check (
    public.user_role() = 'teacher'
    and exists (
      select 1
      from public.questions qu
      join public.quizzes q on q.id = qu.quiz_id
      join public.teacher_assignments ta
        on ta.class_id = q.class_id and ta.subject_id = q.subject_id
      where qu.id = question_options.question_id and ta.teacher_id = auth.uid()
    )
  );

-- ===========================================================================
-- quiz_attempts — students own theirs; teachers/admins/managers read in scope.
-- ===========================================================================
create policy "quiz_attempts_admin_manager_all" on public.quiz_attempts
