      join public.teacher_assignments ta
        on ta.class_id = q.class_id and ta.subject_id = q.subject_id
      where q.id = quiz_attempts.quiz_id and ta.teacher_id = auth.uid()
    )
  );

-- ===========================================================================
-- quiz_answers — same shape as quiz_attempts.
-- ===========================================================================
create policy "quiz_answers_admin_manager_all" on public.quiz_answers
  for all to authenticated
  using (public.user_role() in ('admin', 'manager'))
  with check (public.user_role() in ('admin', 'manager'));

create policy "quiz_answers_student_own_all" on public.quiz_answers
  for all to authenticated
  using (
    exists (
      select 1 from public.quiz_attempts qa
      where qa.id = quiz_answers.attempt_id and qa.student_id = auth.uid()
    )
  )
  with check (
    exists (
      select 1 from public.quiz_attempts qa
      where qa.id = quiz_answers.attempt_id and qa.student_id = auth.uid()
    )
  );

create policy "quiz_answers_teacher_scope_select" on public.quiz_answers
  for select to authenticated
  using (
    public.user_role() = 'teacher'
    and exists (
      select 1
      from public.quiz_attempts qa
      join public.quizzes q on q.id = qa.quiz_id
      join public.teacher_assignments ta
        on ta.class_id = q.class_id and ta.subject_id = q.subject_id
      where qa.id = quiz_answers.attempt_id and ta.teacher_id = auth.uid()
    )
  );

-- ===========================================================================
-- progress — student writes/reads own; teacher/manager/admin read in scope.
-- ===========================================================================
create policy "progress_admin_manager_all" on public.progress
  for all to authenticated
  using (public.user_role() in ('admin', 'manager'))
  with check (public.user_role() in ('admin', 'manager'));

create policy "progress_student_own_all" on public.progress
  for all to authenticated
  using (student_id = auth.uid())
  with check (student_id = auth.uid());

create policy "progress_teacher_scope_select" on public.progress
  for select to authenticated
  using (
    public.user_role() = 'teacher'
    and exists (
      select 1
      from public.resources r
      join public.chapters c on c.id = r.chapter_id
      join public.teacher_assignments ta
        on ta.class_id = c.class_id and ta.subject_id = c.subject_id
      where r.id = progress.resource_id and ta.teacher_id = auth.uid()
    )
  );

-- ===========================================================================
-- notifications — every user owns theirs.
-- ===========================================================================
create policy "notifications_self_all" on public.notifications
  for all to authenticated
  using (user_id = auth.uid())
  with check (user_id = auth.uid());

create policy "notifications_admin_all" on public.notifications
  for all to authenticated
  using (public.user_role() = 'admin')
  with check (public.user_role() = 'admin');

-- ===========================================================================
-- activity_logs — admin reads everything; users read their own.
-- Writes happen server-side via service role only.
-- ===========================================================================
create policy "activity_logs_self_select" on public.activity_logs
  for select to authenticated
  using (user_id = auth.uid());

create policy "activity_logs_admin_select" on public.activity_logs
  for select to authenticated
  using (public.user_role() = 'admin');
